import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

const TaskManager = () => {
  const { staffList, tasks, addTask } = useData();
  const [taskTitle, setTaskTitle] = useState('');
  const [assigneeId, setAssigneeId] = useState('');
  const [dates, setDates] = useState({ startDate: '', deadline: '' });

  const handleCreateTask = (e) => {
    e.preventDefault();
    if (!assigneeId) return alert("Vui lòng chọn nhân sự!");
    if (!dates.startDate || !dates.deadline) return alert("Vui lòng chọn ngày!");
    
    addTask({ 
      title: taskTitle, 
      assigneeId: parseInt(assigneeId),
      startDate: dates.startDate,
      deadline: dates.deadline
    });
    setTaskTitle('');
    setDates({ startDate: '', deadline: '' });
    alert("Đã giao việc thành công");
  };

  return (
    <div>
      <h2>Giao đầu việc</h2>
      <form onSubmit={handleCreateTask} style={{ marginBottom: '30px', padding: '20px', background: '#fff', border: '1px solid #ddd', borderRadius: '8px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '15px' }}>
          <input 
            placeholder="Tên đầu việc" 
            value={taskTitle} 
            onChange={e => setTaskTitle(e.target.value)} 
            required 
            style={{ padding: '8px', width: '90%' }}
          />
          <select 
            value={assigneeId} 
            onChange={e => setAssigneeId(e.target.value)} 
            required 
            style={{ padding: '8px', width: '95%' }}
          >
            <option value="">-- Chọn nhân sự --</option>
            {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
          
          <div>
            <label>Ngày bắt đầu: </label>
            <input type="date" value={dates.startDate} onChange={e => setDates({...dates, startDate: e.target.value})} required />
          </div>
          <div>
            <label>Deadline: </label>
            <input type="date" value={dates.deadline} onChange={e => setDates({...dates, deadline: e.target.value})} required />
          </div>
        </div>
        <button 
            type="submit" 
            style={{ background: '#003366', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }}
          >
            KHỞI TẠO CÔNG VIỆC
        </button>
      </form>

      <h3>Danh sách công việc</h3>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {tasks.map(t => {
          const staff = staffList.find(s => s.id === t.assigneeId);
          return (
            <li key={t.id} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>
              <strong>{t.title}</strong> ({t.startDate} đến {t.deadline}) - Giao cho: {staff?.name} - Tiến độ: {t.progress}%
            </li>
          );
        })}
      </ul>
    </div>
  );
};

export default TaskManager;
